class Solution {
    public int numMusicPlaylists(int n, int goal, int k) {
        final int MOD = 1000000007;
        long[] dp = new long[goal + 1];
        dp[0] = 1;
        for (int i = 1; i <= goal; i++) {
            dp[i] = (i <= n ? i : n) * dp[i - 1];
            if (i - k - 1 >= 0) {
                dp[i] -= (i - k - 1 <= n ? i - k - 1 : n) * dp[i - k - 1];
                dp[i] = (dp[i] + MOD) % MOD;
            }
        }
        return (int) dp[goal];
    }
}
